record.field:
for company in records:
    if company.child_ids:
        try:
            # Create transit warehouse (idempotent)
            company.sudo()._create_transit_warehouse()

            # Setup transit picking types for this company (only if it has real warehouses)
            has_real_wh = bool(env['stock.warehouse'].sudo().search([
                ('company_id', '=', company.id),
                ('is_t4tek_transit_warehouse', '=', False),
            ], limit=1))
            if has_real_wh:
                company.sudo()._create_warehouse_transit_picking_types()

            # Setup transit picking types for each child company (recompute per child)
            for child in company.child_ids:
                child_has_real_wh = bool(env['stock.warehouse'].sudo().search([
                    ('company_id', '=', child.id),
                    ('is_t4tek_transit_warehouse', '=', False),
                ], limit=1))
                if child_has_real_wh:
                    child.sudo()._create_warehouse_transit_picking_types()

        except Exception as e:
            raise Exception("Error creating transit warehouse: %s" % str(e))

# When a warehouse is created, setup transit picking types for that specific warehouse
for warehouse in records:
    if warehouse.company_id:
        try:
            warehouse.company_id.sudo()._create_warehouse_transit_picking_types(warehouse=warehouse)
        except Exception as e:
            raise Exception("Error creating transit picking types for warehouse: %s" % str(e))

if records:
    try:
        records.sudo().automation_handle_company_name_change()
    except Exception as e:
        raise Exception("Transit automation error: %s" % str(e))

# Batch: find all transit picking pairs whose SRC picking is in this trigger batch
transit_pickings = env['t4tek.transit.picking'].search([
    ('src_picking_id', 'in', records.ids)
])

if transit_pickings:
    try:
        transit_pickings.automation_handle_src_picking_done()
    except Exception as e:
        raise Exception("Transit automation error: %s" % str(e))

# records = new src backorder pickings that just became 'assigned'
# Find their PARENT transit pickings via backorder_id
parent_transit_pickings = env['t4tek.transit.picking'].search([
    ('src_picking_id', 'in', records.mapped('backorder_id').ids)
])

if parent_transit_pickings:
    try:
        parent_transit_pickings.automation_handle_src_backorder_ready(records)
    except Exception as e:
        raise Exception("Transit automation error: %s" % str(e))

# Batch: find all transit picking pairs whose DEST picking is in this trigger batch
transit_pickings = env['t4tek.transit.picking'].search([
    ('dest_picking_id', 'in', records.ids)
])

if transit_pickings:
    try:
        transit_pickings.automation_handle_dest_picking_done()
    except Exception as e:
        raise Exception("Transit automation error: %s" % str(e))
